INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00849', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「這期間我看到了一些怵目驚心的文字，譬如說一位經營文藝出版社的朋友這樣寫：『賣書和賣鑽石一 樣……。』我不懂意思，不禁在心中犯嘀咕：『鑽石和書怎麼做比較？』繼續讀下去，才知道他的意思是： 『鑽石價錢昂貴，一個月有那麼幾筆生意就很不錯了。現在賣書也那樣，一個月就只有那麼幾筆。』」下列 何者最符合作者所要表達的意思？', '["讚嘆文藝的可貴", "驚奇書價的昂貴", "感嘆文藝出版的蕭條", "不解讀書風氣的敗壞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00850', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「魚類與鯨豚這兩樣海洋生物資源之豐寡，與背後支撐整個海洋生態系統的海洋環境密切相關。然而，臺灣 社會與海洋生物資源的關係，長期停滯在低層次的腸胃等級。我們過度漁撈，我們隨手將污染擴及海域，造 成東部沿海的魚源處於近臨枯竭的狀態。鯨豚失去食物基礎支撐，快速且大幅減少，因其生態位階高，跌落 更快、更慘。」下列選項何者不是鯨豚數量減少的原因？', '["人類的污染擴大", "鯨豚繁衍能力差", "漁民過度的捕撈", "失去食物鏈基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00851', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「我靜坐水湄一隅，瞧！蘆葦□□著身子，頂著一頭□□般的髮。是由於負荷了過重的鄉思而壓彎了脊樑？ 是因著朝夕守望而愁白了頭嚒？」根據文意，文中的□□依序應是：', '["挺立／青絲", "傾斜／蓬草", "佝僂／銀絲", "搖曳／枯柳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00852', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '下列題辭用語，何者適當？', '["「于歸之喜」：慶賀遷居", "「瓜瓞延祥」：慶賀生孫", "「母儀足式」：慶賀女壽", "「弄璋誌喜」：慶賀生女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00853', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「來自日本東京的鐵道迷藤井英樹，熱愛蒸汽火車。四年前來臺，發現臺灣的蒸汽火車竟然跟日本的一樣， 讓他因此著迷，四年來已造訪臺灣五十次！藤井說，臺鐵修復很多蒸汽火車，因此特別喜歡臺鐵。今年六月 起，連續三個週六，『仲夏寶島號』由玉里開到臺東，藤井英樹特別安排三天來臺灣搭乘。」依據上文，下 列敘述何者最符合文意？', '["臺灣的蒸汽火車吸引日本鐵道迷", "藤井英樹因為喜歡臺灣，特別來臺五十次", "自六月起臺鐵每週六皆開出「仲夏寶島號」", "藤井英樹因為「仲夏寶島號」而熱愛蒸汽火車"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00854', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '下列選項的情感「對象」，並非「朋友」的是：', '["布衣之交不可忘，金蘭之誼常在心", "遙知兄弟登高處，遍插茱萸少一人", "若知四海皆兄弟，何處相逢非故人", "桃花潭水深千尺，不及汪倫送我情"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00855', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '簾外雨潺潺，春意闌珊。羅衾不耐五更寒。夢裡不知身是客，一晌貪歡。獨自莫凭欄，無限江山。別時容易 見時難。流水落花春去也，天上人間（李煜〈浪淘沙〉）。其中「夢裡不知身是客，一晌貪歡」指的是：', '["只有夜夜笙歌，醉生夢死方能排遣苦悶", "貶謫他鄉無可奈何，只好貪圖片刻歡愉", "羈旅漂泊生涯，把人生當作虛幻的夢境", "現實生活苦悶難捱，貪戀夢中短暫歡樂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00856', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「鳥飛到雲中去／鳥群中少了你／太陽落到山稜後／山群中少了你／是的，少了你這風景又怎能印得成記 憶」，下列何者最接近本詩旨意？', '["繁華落盡見真淳", "鳥盡良弓勢必藏", "有了你，生命才有意義", "有遺憾，也是一種美麗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00857', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '陳述古密直知建州浦城縣日，有人失物，捕得，莫知的為盜者。述古乃紿之曰：「某廟有一鐘，能辨盜至靈。」 使人迎置後閤祠之，引群囚立鐘前，自陳：不為盜者摸之則無聲，為盜者摸之則有聲。述古自率同職禱鐘甚 肅，祭訖，以帷圍之，乃陰使人以墨塗鐘。良久，引囚逐一令引手入帷摸之，出乃驗其手，皆有墨，唯有一 囚無墨。訊之，遂承為盜，蓋恐鐘有聲，不敢摸也（沈括《夢溪筆談》）。文中「述古自率同職禱鐘甚肅」 的主要用意為何？', '["假借鬼神之說，使人心生畏懼", "善用辦案工具，期能事半功倍", "官府例行公事，以求辦案順利", "藉由虔誠敬拜，祈求鬼神助佑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00858', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「我的朋友是一位肖像畫家，生活不好過，朋友紛紛給她忠告。大多數人的建議歸結來講就是：『找份正職 吧。』她對我說：『我本來就有正職啊！我是個畫家，他們難道不明白嗎？』……三年過去了，到目前為止， 我的朋友證明了自己是對的。」下列何者，最符合文意？', '["藝術家可以將個人創作視為正職", "創作與謀生彼此衝突而不能兼顧", "藝術無價不必討論現實薪資問題", "有固定收入才是藝術家謀生之道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
